  function getDragAfter(container,y){return [...container.querySelectorAll('.kanban-card:not(.dragging)')].reduce((closest,child)=>{const box=child.getBoundingClientRect();const offset=y-box.top-box.height/2;return offset<0&&offset>closest.offset?{offset,element:child}:closest},{offset:Number.NEGATIVE_INFINITY,element:null}).element}
  function initDrag(){ $$('#pipeline .kanban-card.v23-card').forEach(card=>{card.addEventListener('click',e=>{if(e.target.closest('a,button'))return;openLead(leadById(card.dataset.id))});card.addEventListener('dragstart',e=>{dragId=card.dataset.id;card.classList.add('dragging');try{e.dataTransfer.setData('text/plain',dragId)}catch(_){ }placeholder=document.createElement('div');placeholder.className='col-drop-zone';setTimeout(()=>{card.style.display='none'},0)});card.addEventListener('dragend',()=>{card.style.display='';card.classList.remove('dragging');$$('#pipeline .col').forEach(c=>c.classList.remove('v23-drop'));if(placeholder){placeholder.remove();placeholder=null}dragId=null})}); $$('#pipeline .col').forEach(col=>{const body=col.querySelector('.col-body');if(!body)return;col.addEventListener('dragover',e=>{e.preventDefault();if(col.classList.contains('v23-collapsed'))return;col.classList.add('v23-drop');if(!placeholder)return;const after=getDragAfter(body,e.clientY);after?body.insertBefore(placeholder,after):body.appendChild(placeholder)});col.addEventListener('dragleave',e=>{if(!col.contains(e.relatedTarget))col.classList.remove('v23-drop')});col.addEventListener('drop',e=>{e.preventDefault();col.classList.remove('v23-drop');const id=dragId||e.dataTransfer.getData('text/plain');moveLead(id,col.dataset.col)})})}
  function moveLead(id,stage){const l=leadById(id);if(!l||!stage)return;const old=l.etapa;l.etapa=stage;l.probabilidade=stageCfg(stage).prob;l.ultimaAtualizacao=today();try{if(typeof addAtividade==='function')addAtividade(l.id||l.nome,'Etapa',`Movido de ${old||'—'} para ${stage}`)}catch(e){}saveData();renderPipelineV23();try{typeof showToast==='function'&&showToast(`${l.nome||'Lead'} movido para ${stage}`,'success')}catch(e){}}
